'use client';
// src/components/WelcomeScreen.jsx
import React from 'react';
import WaveVisualizer from './WaveVisualizer';
import TextConsole from './TextConsole';

export default function WelcomeScreen({
  isListening,
  inputText,
  setInputText,
  onToggleListening,
  onSubmitText,
  onPreset,
}) {
  return (
    <section className="kiosk-screen screen-welcome active" id="screenWelcome">
      <div className="welcome-logo">
        <div className="welcome-logo-icon">🎙️</div>
      </div>

      <h2 className="welcome-title">Welcome to Smart Airport Helpdesk</h2>
      <p className="welcome-subtitle">
        We are here to assist you. Please tap the button to speak your request, or type in English below.
        Our system will analyze and adapt to your language.
      </p>

      <div className="welcome-interaction-panel">
        {/* Voice Button */}
        <div className="voice-button-container">
          <button
            className={`voice-btn${isListening ? ' listening' : ''}`}
            id="voiceBtn"
            title="Tap to Speak"
            onClick={onToggleListening}
          >
            🎙️
          </button>
          <div className={`listening-text${isListening ? ' active' : ''}`}>
            {isListening ? 'Listening...' : 'Tap to Speak'}
          </div>
          <WaveVisualizer active={isListening} />
        </div>

        {/* Text Console + Presets */}
        <TextConsole
          inputText={inputText}
          setInputText={setInputText}
          onSubmit={onSubmitText}
          onPreset={onPreset}
        />
      </div>
    </section>
  );
}
