'use client';
// src/hooks/useKiosk.js — Redesigned for 3-screen flow:
// WELCOME → REQUEST (voice/text + analysis) → CHAT (translated chatbox)

import { useState, useRef, useCallback, useEffect } from 'react';
import { analyzeEnglishText, getBaseLangCode } from '../data/nliRules';
import { CHATBOT_DATABASE, getChatbotDbKey } from '../data/chatbotData';

export default function useKiosk() {
  // --- Screens: 'WELCOME' | 'REQUEST' | 'CHAT' ---
  const [currentScreen, setCurrentScreen] = useState('WELCOME');

  // --- Language ---
  const [selectedLanguage, setSelectedLanguage] = useState('en');

  // --- Status ---
  const [kioskStatus, setKioskStatus] = useState('ready');

  // --- Input ---
  const [inputText, setInputText] = useState('');
  const [isListening, setIsListening] = useState(false);

  // --- Analysis results (shown inline on REQUEST screen) ---
  const [analysisResult, setAnalysisResult] = useState(null); // { probabilities, rawMatches, highlightedHtml, detected }
  const [analysisComplete, setAnalysisComplete] = useState(false);

  // --- Language Suggestion overlay ---
  const [showSuggestion, setShowSuggestion] = useState(false);
  const [suggestionData, setSuggestionData] = useState(null);

  // --- Chat ---
  const [chatMessages, setChatMessages] = useState([]);

  // --- Toast ---
  const [toast, setToast] = useState(null);

  const recognizerRef = useRef(null);
  const highestInterimRef = useRef(null);

  const showToast = useCallback((message, type = 'info') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 5000);
  }, []);

  // Init speech recognition
  useEffect(() => {
    const SpeechObj = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechObj) return;
    try {
      const rec = new SpeechObj();
      rec.continuous = false;
      rec.interimResults = true;
      rec.lang = 'en-US';

      rec.onstart = () => {
        setIsListening(true);
        highestInterimRef.current = null;
        setKioskStatus('listening');
      };

      rec.onresult = (event) => {
        let interim = '', final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        const text = final || interim;
        if (text) {
          setInputText(text);
          const a = analyzeEnglishText(text);
          if (a.detected && (!highestInterimRef.current || a.detected.confidence > highestInterimRef.current.confidence)) {
            highestInterimRef.current = a.detected;
          }
        }
      };

      rec.onerror = (e) => {
        setIsListening(false);
        setKioskStatus('ready');
        if (e.error === 'not-allowed') showToast('Microphone blocked! Allow mic in browser settings.', 'error');
        else if (e.error === 'no-speech') showToast('No speech detected. Please try speaking louder.', 'error');
        else if (e.error === 'network') showToast('Network error. Try typing instead.', 'error');
        else showToast('Mic capture failed. Try typing below.', 'error');
      };

      rec.onend = () => {
        setIsListening(false);
        setKioskStatus('ready');
        setTimeout(() => {
          setInputText(prev => {
            if (prev.trim().length > 3) runAnalysis(prev);
            return prev;
          });
        }, 300);
      };

      recognizerRef.current = rec;
    } catch (err) {
      console.warn('Speech init failed:', err);
    }
  }, []);

  const toggleListening = useCallback(() => {
    if (!recognizerRef.current) {
      showToast('Microphone not supported in this browser.', 'error');
      return;
    }
    if (isListening) {
      recognizerRef.current.stop();
    } else {
      setInputText('');
      setAnalysisResult(null);
      setAnalysisComplete(false);
      try { recognizerRef.current.start(); } catch (e) { console.warn(e); }
    }
  }, [isListening, showToast]);

  // Run NLI analysis and show results inline
  const runAnalysis = useCallback((text) => {
    if (!text || !text.trim()) return;
    setKioskStatus('thinking');
    setAnalysisComplete(false);

    // Small delay to let user see "Analyzing..." state
    setTimeout(() => {
      const result = analyzeEnglishText(text);
      setAnalysisResult(result);
      setAnalysisComplete(true);
      setKioskStatus('ready');

      const resolved = result.detected || highestInterimRef.current;
      highestInterimRef.current = null;

      if (resolved) {
        // After 1.5s, show the language suggestion popup
        setTimeout(() => {
          setSuggestionData({ detected: resolved, probabilities: result.probabilities });
          setShowSuggestion(true);
          setKioskStatus('prompt');
        }, 1500);
      } else {
        // No L1 detected — go straight to English chat
        setTimeout(() => proceedToChat('en'), 1800);
      }
    }, 600);
  }, []);

  const submitRequest = useCallback((text) => {
    if (!text || !text.trim()) return;
    runAnalysis(text);
  }, [runAnalysis]);

  // User chose a language (or kept English)
  const proceedToChat = useCallback((langCode) => {
    setSelectedLanguage(langCode);
    setShowSuggestion(false);
    setKioskStatus('ready');

    // Init chatbot with welcome message in chosen language
    const dbKey = getChatbotDbKey(langCode);
    const db = CHATBOT_DATABASE[dbKey] || CHATBOT_DATABASE.en;
    setChatMessages([{ sender: 'bot', text: db.welcome }]);

    setCurrentScreen('CHAT');
  }, []);

  const sendChatMessage = useCallback((query) => {
    if (!query.trim()) return;
    setChatMessages(prev => [...prev, { sender: 'user', text: query }]);

    setTimeout(() => {
      const dbKey = getChatbotDbKey(selectedLanguage);
      const db = CHATBOT_DATABASE[dbKey] || CHATBOT_DATABASE.en;
      const lowerQuery = query.toLowerCase();
      let found = null;
      for (const item of db.answers) {
        if (item.keys.some(k => lowerQuery.includes(k))) { found = item.ans; break; }
      }
      setChatMessages(prev => [...prev, { sender: 'bot', text: found || db.fallback }]);
    }, 700);
  }, [selectedLanguage]);

  const resetSession = useCallback(() => {
    setCurrentScreen('WELCOME');
    setSelectedLanguage('en');
    setInputText('');
    setAnalysisResult(null);
    setAnalysisComplete(false);
    setShowSuggestion(false);
    setSuggestionData(null);
    setChatMessages([]);
    setKioskStatus('ready');
    highestInterimRef.current = null;
  }, []);

  const goToRequest = useCallback(() => {
    setCurrentScreen('REQUEST');
    setInputText('');
    setAnalysisResult(null);
    setAnalysisComplete(false);
  }, []);

  return {
    currentScreen, selectedLanguage, kioskStatus,
    inputText, setInputText, isListening,
    analysisResult, analysisComplete,
    showSuggestion, setSuggestion: setShowSuggestion,
    suggestionData,
    chatMessages,
    toast,
    // Actions
    goToRequest, toggleListening, submitRequest,
    proceedToChat, sendChatMessage, resetSession, showToast,
  };
}
