'use client';
// src/components/modals/ChatbotModal.jsx
import React, { useState, useRef, useEffect } from 'react';

export default function ChatbotModal({ visible, onClose, chatMessages, onSend }) {
  const [input, setInput] = useState('');
  const messagesRef = useRef(null);

  useEffect(() => {
    if (messagesRef.current) {
      messagesRef.current.scrollTop = messagesRef.current.scrollHeight;
    }
  }, [chatMessages]);

  const handleSend = () => {
    if (!input.trim()) return;
    onSend(input.trim());
    setInput('');
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <div className={`portal-overlay-modal${visible ? ' active' : ''}`} onClick={onClose}>
      <div className="portal-modal-card" onClick={(e) => e.stopPropagation()}>
        <div className="portal-modal-header">
          <h4 className="portal-modal-title">🤖 Airport Helpdesk Chatbot</h4>
          <button className="portal-modal-close" onClick={onClose}>×</button>
        </div>
        <div className="portal-modal-body">
          <div className="chat-container">
            <div className="chat-messages" ref={messagesRef}>
              {chatMessages.map((msg, i) => (
                <div key={i} className={`chat-bubble ${msg.sender}`}>
                  {msg.text}
                </div>
              ))}
              {chatMessages.length === 0 && (
                <div className="chat-bubble bot">Hello! How can I help you today at the terminal?</div>
              )}
            </div>
            <div className="chat-input-bar">
              <input
                type="text"
                className="chat-input"
                placeholder='Ask e.g., "Where is baggage claim?"...'
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
              />
              <button className="chat-send-btn" onClick={handleSend}>Send</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
