'use client';
// src/components/LanguageSuggestionOverlay.jsx
import React from 'react';

export default function LanguageSuggestionOverlay({ visible, suggestionData, onSelectLanguage, onDecline }) {
  if (!suggestionData) return null;
  const { detected } = suggestionData;

  return (
    <div className={`suggestion-overlay${visible ? ' active' : ''}`} onClick={onDecline}>
      <div className="suggestion-card" onClick={(e) => e.stopPropagation()}>
        <div className="suggestion-orb-holder">
          <span className="suggestion-flag-icon">{detected?.flag || '🗺️'}</span>
        </div>
        <h3 className="suggestion-title">
          Traced Native Language: {detected?.name || 'Unknown'}
        </h3>
        <p className="suggestion-desc">
          Our NLI engine analyzed your input patterns and identified a{' '}
          <strong>{detected?.confidence}% confidence</strong> of{' '}
          <strong>{detected?.name} ({detected?.nativeName})</strong> linguistic transfer.
          Please choose your preferred layout below, or continue in English:
        </p>

        <div className="suggestion-options-grid">
          {(detected?.choices || []).map((choice) => (
            <button
              key={choice.code}
              className="suggest-lang-option-btn"
              onClick={() => onSelectLanguage(choice.code)}
            >
              <div className="suggest-lang-left">
                <span className="suggest-lang-flag">{choice.flag}</span>
                <div className="suggest-lang-names">
                  <span className="suggest-lang-native">{choice.nativeName}</span>
                  <span className="suggest-lang-standard">Switch to {choice.name}</span>
                </div>
              </div>
              <span className="suggest-lang-match">{choice.desc}</span>
            </button>
          ))}
        </div>

        <div className="suggestion-actions" style={{ marginTop: '8px', width: '100%' }}>
          <button className="btn-secondary" style={{ width: '100%' }} onClick={onDecline}>
            Keep English (Continue in English)
          </button>
        </div>
      </div>
    </div>
  );
}
